var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"심문이라도 하려고 부른 줄 알았더니, 날 아예 네 편으로 삼으시겠다?","JPN":"呼び出されて尋問でもされると思ったら、俺をお前の味方にするだって？","ENG":"I thought you were going to interrogate me. And it turns out you want to win me over?","TWN":"我還以為你找我來是要審問我，結果是要把我變成你的人嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"내가 남의 장단 맞춰주는데 이렇게나 소질이 있는 줄은 몰랐는걸?","JPN":"俺が他人にあわせてやる才能があるとは思わなかったんだが。","ENG":"I'm good at playing along, am I not?","TWN":"我是很能配合別人啦，只是沒想到竟然有人因此不想放我走。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm...","TWN":"嗯。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아. 계획이 바뀌었어.","JPN":"よし。計画が変わった。","ENG":"Alright, change of plan.","TWN":"好吧！計畫改變！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"적당히 털어먹고 빠지려 했는데, 그것보단 여기 남아있는 게 좋을 것 같아.","JPN":"適当にちょろまかして消えるつもりだったが、ここに残っていたほうがよさそうだ。","ENG":"I was going to empty your pockets and leave. I think I'm just going to stay.","TWN":"本來是想吃乾抹淨後就閃人，但留在這裡好像更不錯。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여기 쓸만한 것들이 잔뜩 남아있는데, 전부 두고 가버리기엔 아깝잖아?","JPN":"ここには使えそうなものが大量に残っているのに、全部置いていくなんてもったいないだろ？","ENG":"There are so many useful things here that I don't want to leave behind.","TWN":"這裡還有許多不錯的東西，放棄這些東西就這樣離開似乎有點可惜？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아, 걱정 마. 너희 직원을 납치하거나 돈을 훔치겠다고는 안 했으니까.","JPN":"ああ、心配すんなよ。お前の社員をさらったり金を盗むとは言ってないぞ。","ENG":"Ah, don’t worry. I'm not going to abduct your employees or rob them.","TWN":"放心啦！我不會綁架你的員工或是偷錢啦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"다른 해적들이라면 몰라도, 난 사람을 소유하는 취미는 없거든.","JPN":"他の海賊は知らないけど、俺は人を所有する趣味はない。","ENG":"I don't know about other pirates, but I'm not interested in owning people.","TWN":"其他海盜我是不清楚，但我對人沒興趣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래, 적어도 널 만나기 전까진 그랬지.","JPN":"そう、少なくともお前に出会う前はそうだった。","ENG":"Well, at least before I met you.","TWN":"嗯，至少在遇見你之前是這樣的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"만약 그 로봇이 네 본체였다면 난 진작에 널 내 걸로 만들어서 여길 떴을 거야.","JPN":"もしそのロボットがお前の本体だったら、俺はとっくの昔にお前を自分のものにしてここから去っていったはずだ。","ENG":"If that robot really was you, I would have stolen you away with me a long time ago.","TWN":"如果你是機器人的話，我早就把你打包帶走了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 인간이란 걸 알게 된 지금도, 여전히 네가 갖고 싶단 말이지.","JPN":"しかし、中身が人間ということを知った今なお、お前がほしい。","ENG":"I want to own you so badly, even though I know you're human.","TWN":"不過發現你是人類後，我還是很想把你據為己有。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"내가 널 통제할 수 있을지 시험하고 싶어졌어.","JPN":"俺がお前をコントロールできるか試してみたくなった。","ENG":"I want to see if I can control you.","TWN":"因為我想實驗看看，我可以控制你嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그럼, 우리 사이좋게 잘 지내보자고?","JPN":"じゃあ、これから仲良くしようぜ。","ENG":"So, let's be friends, shall we?","TWN":"那我們就好好相處吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};